def verticalOrder(root):
    if not root: return []
    m = collections.defaultdict(list); q = collections.deque([(root, 0)])
    while q:
        node, col = q.popleft()
        m[col].append(node.val)
        if node.left: q.append((node.left, col - 1))
        if node.right: q.append((node.right, col + 1))
    return [m[i] for i in sorted(m.keys())]

